package main

import (
	"errors"
	"fmt"
	"os/exec"
	"regexp"
	"strconv"
	"strings"
)

// MeasureLatency pings the specified host the given number of times and returns the average latency in milliseconds.
// It uses the system 'ping' command via os/exec and parses the output to extract the average RTT.
// Supports Unix-like systems (Linux, macOS, BSD, BusyBox). For Windows support, additional output parsing adjustments are required.
func MeasureLatency(host string, count int) (float64, error) {
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be positive")
	}

	// Execute ping directly without a shell to avoid injection vulnerabilities and remove bash dependency
	cmd := exec.Command("ping", "-c", strconv.Itoa(count), host)
	output, err := cmd.CombinedOutput()
	if err != nil {
		var exitErr *exec.ExitError
		// Only return early if the command failed to execute entirely (not just non-zero exit code)
		if !errors.As(err, &exitErr) {
			return 0, fmt.Errorf("failed to execute ping: %w (output: %s)", err, string(output))
		}
		// Continue parsing output even if ping exited with non-zero (e.g. partial packet loss)
	}

	outputStr := string(output)
	lines := strings.Split(outputStr, "\n")
	var statsLine string
	for _, line := range lines {
		// Match common min/avg/max substring present in all Unix-like ping stats lines
		if strings.Contains(line, "min/avg/max") {
			statsLine = line
			break
		}
	}

	if statsLine == "" {
		return 0, errors.New("could not find RTT statistics in ping output")
	}

	// Regex handles both 3-field (min/avg/max for BusyBox) and 4-field (with mdev/stddev for Linux/macOS) formats
	// Allows optional spaces around the equals sign and before the ms unit
	re := regexp.MustCompile(`= *[\d.]+/([\d.]+)/[\d.]+(?:/[\d.]+)? *ms`)
	matches := re.FindStringSubmatch(statsLine)
	if len(matches) < 2 {
		return 0, errors.New("failed to parse average latency from ping output")
	}

	avgStr := matches[1]
	avg, err := strconv.ParseFloat(avgStr, 64)
	if err != nil {
		return 0, fmt.Errorf("failed to convert average latency to float: %w", err)
	}

	return avg, nil
}

