	outputStr := string(output)
	lines := strings.Split(outputStr, "\n")
	var avgStr string
	if runtime.GOOS == "windows" {
		// Parse Windows ping output format, handles <1ms edge case
		re := regexp.MustCompile(`Average = (?:<1|(\d+(?:\.\d+)?)) *ms`)
		for _, line := range lines {
			if strings.Contains(line, "Average =") {
				matches := re.FindStringSubmatch(line)
				if len(matches) >= 2 {
					if matches[1] == "" {
						avgStr = "0.5" // Approximate sub-millisecond latency as 0.5ms
					} else {
						avgStr = matches[1]
					}
					break
				}
			}
		}
	} else {
		// Parse Unix-like ping output (Linux, macOS, BSD, etc.)
		var statsLine string
		for _, line := range lines {
			if strings.Contains(line, "min/avg/max") {
				statsLine = line
				break
			}
		}
		if statsLine == "" {
			return 0, errors.New("could not find RTT statistics in ping output")
		}
		// Regex matches both Linux (rtt/mdev) and macOS (round-trip/stddev) summary formats
		re := regexp.MustCompile(`(?:rtt|round-trip) min/avg/max/(?:mdev|stddev) = \d+(?:\.\d+)?/([\d.]+)/\d+(?:\.\d+)?/\d+(?:\.\d+)? ms`)
		matches := re.FindStringSubmatch(statsLine)
		if len(matches) < 2 {
			return 0, errors.New("failed to parse average latency from ping output")
		}
		avgStr = matches[1]
	}
	if avgStr == "" {
		return 0, errors.New("could not extract average latency from ping output")
	}
	avg, err := strconv.ParseFloat(avgStr, 64)
	if err!= nil {
		return 0, fmt.Errorf("failed to convert average latency to float: %w", err)
	}
	return avg, nil
}

