package main
import (
	"errors"
	"fmt"
	"os/exec"
	"regexp"
	"runtime"
	"strconv"
	"strings"
)
var (
	unixRttRegex    = regexp.MustCompile(`(?:rtt|round-trip) min/avg/max/(?:mdev|stddev) = \d+\.?\d*/([\d.]+)/\d+\.?\d*/\d+\.?\d* ms`)
	windowsAvgRegex = regexp.MustCompile(`Average = (\d+\.?\d*)\s*ms`)
)
// MeasureLatency pings the specified host the given number of times and returns the average latency in milliseconds.
// It uses the system 'ping' command via os/exec and parses the output to extract the average RTT.
func MeasureLatency(host string, count int) (float64, error) {
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be positive")
	}
	// Build ping command arguments based on OS to avoid shell injection and ensure cross-platform compatibility
	var args []string
	if runtime.GOOS == "windows" {
		args = []string{"-n", strconv.Itoa(count)}
	} else {
		args = []string{"-c", strconv.Itoa(count)}
	}
	args = append(args, host)
	cmd := exec.Command("ping", args...)
	var exitErr *exec.ExitError
	output, err := cmd.CombinedOutput()
	if err!= nil {
		// Only return error if the command couldn't be executed at all (not for non-zero exit codes like partial packet loss)
		if!errors.As(err, &exitErr) {
			return 0, fmt.Errorf("failed to execute ping: %w", err)
		}
	}
	outputStr := string(output)
	// Try matching Unix-style RTT line first (Linux/macOS/BSD)
	matches := unixRttRegex.FindStringSubmatch(outputStr)
	if len(matches) < 2 {
		// Fall back to Windows-style average line
		matches = windowsAvgRegex.FindStringSubmatch(outputStr)
		if len(matches) < 2 {
			if exitErr!= nil {
				return 0, fmt.Errorf("ping failed with exit code %d: could not find average latency in output: %q", exitErr.ExitCode(), outputStr)
			}
			return 0, fmt.Errorf("could not find average latency in ping output: %q", outputStr)
