package main

import (
	"errors"
	"fmt"
	"os"
	"os/exec"
	"regexp"
	"runtime"
	"strconv"
)

var (
	unixPingAvgRegex    = regexp.MustCompile(`(?:rtt|round-trip)\s+min/avg/max(?:/\w+)?\s*=\s*[\d.]+\s*/\s*([\d.]+)\s*/`)
	windowsPingAvgRegex = regexp.MustCompile(`(?i)Average\s*=\s*([\d.]+)\s*ms`)
)

func MeasureLatency(host string, count int) (float64, error) {
	if count <= 0 {
		return 0, errors.New("count must be greater than 0")
	}

	var args []string
	if runtime.GOOS == "windows" {
		args = []string{"-n", strconv.Itoa(count), host}
	} else {
		args = []string{"-c", strconv.Itoa(count), host}
	}

	cmd := exec.Command("ping", args...)
	output, err := cmd.CombinedOutput()
	outputStr := string(output)

	var avgStr string
	if runtime.GOOS == "windows" {
		matches := windowsPingAvgRegex.FindStringSubmatch(outputStr)
		if len(matches) < 2 {
			if err!= nil {
				return 0, fmt.Errorf("ping failed: %w, output: %s", err, outputStr)
			}
			return 0, fmt.Errorf("failed to parse ping output: %s", outputStr)
		}
		avgStr = matches[1]
	} else {
		matches := unixPingAvgRegex.FindStringSubmatch(outputStr)
		if len(matches) < 2 {
			if err!= nil {
				return 0, fmt.Errorf("ping failed: %w, output: %s", err, outputStr)
			}
			return 0, fmt.Errorf("failed to parse ping output: %s", outputStr)
		}
		avgStr = matches[1]
	}

	avg, err := strconv.ParseFloat(avgStr, 64)
	if err!= nil {
		return 0, fmt.Errorf("failed to parse average latency '%s': %w", avgStr, err)
	}

	return avg, nil
}

func main() {
	if len(os.Args)!= 3 {
		fmt.Printf("Usage: %s <host> <count>\n", os.Args[0])
		os.Exit(1)
	}

	host := os.Args[1]
	countStr := os.Args[2]
	count, err := strconv.Atoi(countStr)
	if err!= nil {
		fmt.Printf("Invalid count: %v\n", err)
		os.Exit(1)
	}

	avg, err := MeasureLatency(host, count)
	if err!= nil {
		fmt.Printf("Failed to measure latency: %v\n", err)
		os.Exit(1)
	}

	fmt.Printf("Average latency to %s (%d pings): %.2f ms\n", host, count, avg)
}

