package main
import (
	"errors"
	"fmt"
	"os/exec"
	"runtime"
	"strconv"
	"strings"
)
// MeasureLatency pings the specified host the given number of times and returns the average latency in milliseconds.
// It uses the system 'ping' command via os/exec and parses the output to extract the average RTT.
func MeasureLatency(host string, count int) (float64, error) {
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be positive")
	}
	// Build ping command arguments based on OS to avoid shell injection and improve portability
	var args []string
	switch runtime.GOOS {
	case "windows":
		args = []string{"-n", strconv.Itoa(count)} // Windows uses -n for count
	default:
		args = []string{"-c", strconv.Itoa(count)} // Unix-like systems use -c for count
	}
	args = append(args, host)
	// Execute ping directly without shell to prevent injection attacks
	cmd := exec.Command("ping", args...)
	output, cmdErr := cmd.CombinedOutput()
	// Normalize line endings to handle Windows \r\n
	outputStr := strings.ReplaceAll(string(output), "\r", "")
	lines := strings.Split(outputStr, "\n")
	var avg float64
	var parseErr error
	switch runtime.GOOS {
	case "windows":
		// Parse Windows ping output format
		found := false
		for _, line := range lines {
			if strings.Contains(line, "Average =") {
				avgParts := strings.SplitN(line, "Average =", 2)
				if len(avgParts) < 2 {
					continue
				}
				avgStr := strings.TrimSpace(avgParts[1])
				avgStr = strings.TrimSuffix(avgStr, "ms")
				avgStr = strings.TrimSpace(avgStr)
				avg, parseErr = strconv.ParseFloat(avgStr, 64)
				if parseErr == nil {
					found = true
					break
				}
			}
		}
		if!found && parseErr == nil {
			parseErr = errors.New("no average latency line found in Windows ping output")
		}
	default:
		// Parse Unix-like (Linux, macOS, BSD) ping output format
		found := false
		for _, line := range lines {
			// Match summary line present in both Linux (rtt.) and macOS (round-trip.) output
			if strings.Contains(line, "min/avg/max") {
				eqParts := strings.SplitN(line, "=", 2)
				if len(eqParts) < 2 {
					continue
				}
				statsPart := strings.TrimSpace(eqParts[1])
				slashParts := strings.Split(statsPart, "/")
				if len(slashParts) < 2 {
					continue
				}
				// Average is the second value in min/avg/max/[mdev/stddev] sequence
				avgStr := strings.TrimSpace(slashParts[1])
				avg, parseErr = strconv.ParseFloat(avgStr, 64)
				if parseErr == nil {
					found = true
					break
				}
			}
		}
		if!found && parseErr == nil {
			parseErr = errors.New("no RTT statistics line found in ping output")
		}
	}
	// Return average if parsing succeeded, even if ping exited with non-zero (partial success)
	if parseErr == nil {
		return avg, nil
	}
	// Combine errors for better debugging context
	if cmdErr!= nil {
		return 0, fmt.Errorf("ping execution failed: %w (parse error: %w, output: %q)", cmdErr, parseErr, outputStr)
	}
	return 0, fmt.Errorf("failed to parse ping output: %w (output: %q)", parseErr, outputStr)
}

