	cmd := exec.Command("ping", args...)
	output, err := cmd.CombinedOutput()
	outputStr := string(output)
	// Attempt to parse output even if command returned error (handles partial packet loss cases)
	avg, parseErr := parsePingOutput(outputStr, runtime.GOOS)
	if parseErr == nil {
