	}
	// Return appropriate error if parsing failed
	if err!= nil {
		return 0, fmt.Errorf("ping command failed: %w, output: %s", err, outputStr)
	}
	return 0, fmt.Errorf("failed to parse ping output: %w, output: %s", parseErr, outputStr)
}
// parsePingOutput extracts average latency from ping command output based on OS
func parsePingOutput(output string, goos string) (float64, error) {
	lines := strings.Split(output, "\n")
	if goos == "windows" {
		// Parse Windows ping output format
		for _, line := range lines {
			trimmedLine := strings.TrimSpace(line)
			if strings.Contains(trimmedLine, "Average = ") {
				avgPart := strings.TrimPrefix(trimmedLine, "Average = ")
				msParts := strings.Split(avgPart, "ms")
				if len(msParts) == 0 {
					return 0, fmt.Errorf("invalid average line format: %s", line)
				}
				numStr := strings.TrimSpace(msParts[0])
				avg, err := strconv.ParseFloat(numStr, 64)
				if err!= nil {
					return 0, fmt.Errorf("failed to parse average value '%s': %w", numStr, err)
				}
				return avg, nil
			}
		}
		return 0, errors.New("no average line found in Windows ping output")
	}
	// Parse Unix-like (Linux, macOS, BSD) ping output format
	for _, line := range lines {
		trimmedLine := strings.TrimSpace(line)
		if strings.Contains(trimmedLine, "min/avg/max") {
			eqParts := strings.Split(trimmedLine, " = ")
			if len(eqParts) < 2 {
				return 0, fmt.Errorf("invalid rtt summary line format: %s", line)
			}
			rttParts := strings.Split(eqParts[1], "/")
			if len(rttParts) < 2 {
				return 0, fmt.Errorf("invalid rtt values format in line: %s", line)
			}
			avgStr := strings.TrimSpace(rttParts[1])
			avg, err := strconv.ParseFloat(avgStr, 64)
			if err!= nil {
				return 0, fmt.Errorf("failed to parse average value '%s': %w", avgStr, err)
			}
			return avg, nil
		}
	}
	return 0, errors.New("no rtt summary line found in ping output")
}
func main() {
