package main

import (
	"errors"
	"fmt"
	"os"
	"os/exec"
	"regexp"
	"strconv"
	"strings"
)

// MeasureLatency pings the specified host the given number of times and returns the average latency in milliseconds.
// It uses the system 'ping' command via os/exec and parses the output to extract the average RTT.
// Compatible with Unix-like systems (Linux, macOS) using standard ping implementations.
func MeasureLatency(host string, count int) (float64, error) {
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be positive")
	}

	// Execute ping directly without shell to eliminate command injection risks and quoting issues
	cmd := exec.Command("ping", "-c", strconv.Itoa(count), host)
	output, cmdErr := cmd.CombinedOutput()
	outputStr := string(output)

	// Only return error immediately if the command failed to start (not just non-zero exit)
	if cmdErr != nil {
		var exitErr *exec.ExitError
		if !errors.As(cmdErr, &exitErr) {
			return 0, fmt.Errorf("failed to start ping command: %w", cmdErr)
		}
		// Proceed to parse output even for non-zero exit codes (e.g, partial packet loss may still have RTT data)
	}

	// Locate the RTT statistics line (works for both Linux "rtt" and macOS "round-trip" prefixes)
	lines := strings.Split(outputStr, "\n")
	var statsLine string
	for _, line := range lines {
		if strings.Contains(line, "min/avg/max") {
			statsLine = line
			break
		}
	}

	if statsLine == "" {
		if cmdErr != nil {
			return 0, fmt.Errorf("could not find RTT statistics: command exited with error: %w (output: %q)", cmdErr, outputStr)
		}
		return 0, fmt.Errorf("could not find RTT statistics in ping output (output: %q)", outputStr)
	}

	// Regex pattern compatible with Linux (mdev) and macOS (stddev) ping output formats
	re := regexp.MustCompile(`(?:rtt|round-trip) min/avg/max/(?:mdev|stddev) = \d+\.\d+/([\d.]+)/\d+\.\d+/\d+\.\d+ ms`)
	matches := re.FindStringSubmatch(statsLine)
	if len(matches) < 2 {
		if cmdErr != nil {
			return 0, fmt.Errorf("failed to parse average latency: command exited with error: %w (stats line: %q, full output: %q)", cmdErr, statsLine, outputStr)
		}
		return 0, fmt.Errorf("failed to parse average latency from stats line: %q (full output: %q)", statsLine, outputStr)
	}

	avgStr := matches[1]
	avg, err := strconv.ParseFloat(avgStr, 64)
	if err != nil {
		baseErr := fmt.Errorf("failed to parse average latency value '%s': %w", avgStr, err)
		if cmdErr != nil {
			return 0, fmt.Errorf("%w: command exited with error: %w (full output: %q)", baseErr, cmdErr, outputStr)
		}
		return 0, baseErr
	}

	return avg, nil
}

func main() {
	if len(os.Args) != 3 {
		fmt.Printf("Usage: %s <host> <ping-count>\n", os.Args[0])
		os.Exit(1)
	}

	host := os.Args[1]
	countStr := os.Args[2]
	count, err := strconv.Atoi(countStr)
	if err != nil {
		fmt.Printf("Invalid count: must be a positive integer: %v\n", err)
		os.Exit(1)
	}

	avgLatency, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Latency measurement failed: %v\n", err)
		os.Exit(1)
	}

	fmt.Printf("Average latency to %s over %d pings: %.2f ms\n", host, count, avgLatency)
}

