package main

import (
	"errors"
	"fmt"
	"os"
	"os/exec"
	"regexp"
	"runtime"
	"strconv"
)

// MeasureLatency pings the specified host count times and returns the average latency in milliseconds.
// It uses the system's native ping command via os/exec, with cross-platform support for Windows, Linux, and macOS.
func MeasureLatency(host string, count int) (float64, error) {
	// Validate input parameters
	if count < 1 {
		return 0, errors.New("count must be a positive integer (at least 1)")
	}
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}

	countStr := strconv.Itoa(count)
	var cmd *exec.Cmd

	// Construct platform-appropriate ping command
	switch runtime.GOOS {
	case "windows":
		cmd = exec.Command("ping", "-n", countStr, host)
	default:
		// Unix-like systems (Linux, macOS, BSD) use -c flag for packet count
		cmd = exec.Command("ping", "-c", countStr, host)
	}

	// Execute command and capture combined stdout/stderr for error context
	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("ping execution failed: %w\nOutput: %s", err, string(output))
	}

	outputStr := string(output)
	var avgStr string

	// Parse output based on operating system's ping format
	switch runtime.GOOS {
	case "windows":
		// Matches Windows ping summary line: "Average = Xms" (supports integer and float values)
		re := regexp.MustCompile(`Average\s*=\s*(\d+\.?\d*)\s*ms`)
		match := re.FindStringSubmatch(outputStr)
		if len(match) < 2 {
			return 0, fmt.Errorf("failed to extract average from Windows ping output:\n%s", outputStr)
		}
		avgStr = match[1]
	default:
		// Matches Unix-like ping summaries:
		// Linux: "rtt min/avg/max/mdev = 1.2/3.4/5.6/7.8 ms"
		// macOS: "round-trip min/avg/max/stddev = 1.2/3.4/5.6/7.8 ms"
		re := regexp.MustCompile(`(?:rtt|round-trip).*=\s*(\d+\.?\d*)/(\d+\.?\d*)/(\d+\.?\d*)/`)
		match := re.FindStringSubmatch(outputStr)
		if len(match) < 3 {
			return 0, fmt.Errorf("failed to extract average from Unix ping output:\n%s", outputStr)
		}
		avgStr = match[2] // Second capture group is the average value
	}

	// Convert average string to float64
	avgLatency, err := strconv.ParseFloat(avgStr, 64)
	if err != nil {
		return 0, fmt.Errorf("failed to parse average value '%s': %w", avgStr, err)
	}

	return avgLatency, nil
}

func main() {
	// Handle command line arguments for user configuration
	if len(os.Args) != 3 {
		fmt.Printf("Usage: %s <target-host> <ping-count>\nExample: %s google.com 4\n", os.Args[0], os.Args[0])
		os.Exit(1)
	}

	host := os.Args[1]
	countStr := os.Args[2]

	// Parse count input to integer
	count, err := strconv.Atoi(countStr)
	if err != nil {
		fmt.Printf("Error: Invalid ping count '%s' - must be a positive integer\n", countStr)
		os.Exit(1)
	}

	// Run latency measurement
	avg, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Latency measurement failed: %v\n", err)
		os.Exit(1)
	}

	// Print result
	fmt.Printf("Average latency to %s over %d pings: %.2f ms\n", host, count, avg)
}

