package main
import (
	"errors"
	"fmt"
	"os/exec"
	"regexp"
	"strconv"
	"strings"
)
// MeasureLatency pings the specified host the given number of times and returns the average latency in milliseconds.
// It uses the system 'ping' command via os/exec and parses the output to extract the average RTT of successful pings.
// Compatible with Unix-like systems (Linux, macOS, BSD).
func MeasureLatency(host string, count int) (float64, error) {
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be positive")
	}
	// Execute ping directly without shell to eliminate command injection risk and bash dependency
	cmd := exec.Command("ping", "-c", strconv.Itoa(count), host)
	output, cmdErr := cmd.CombinedOutput()
	outputStr := string(output)
	lines := strings.Split(outputStr, "\n")
	var statsLine string
	for _, line := range lines {
		trimmedLine := strings.TrimSpace(line)
		if strings.Contains(trimmedLine, "min/avg/max") {
			statsLine = trimmedLine
			break
		}
	}
	if statsLine == "" {
		if cmdErr!= nil {
			return 0, fmt.Errorf("ping command failed: %w (output: %q)", cmdErr, outputStr)
		}
		return 0, errors.New("could not find RTT statistics in ping output")
	}
	// Regex matches both Linux (rtt/mdev) and macOS/BSD (round-trip/stddev) ping statistics formats
	re := regexp.MustCompile(`^(?:rtt|round-trip)\s+min/avg/max/(?:mdev|stddev)\s*=\s*\d+(?:\.\d+)?/([\d.]+)/\d+(?:\.\d+)?/\d+(?:\.\d+)?\s+ms$`)
	matches := re.FindStringSubmatch(statsLine)
	if len(matches) < 2 {
		if cmdErr!= nil {
			return 0, fmt.Errorf("ping command failed: %w, failed to parse average latency from line: %q (full output: %q)", cmdErr, statsLine, outputStr)
		}
		return 0, fmt.Errorf("failed to parse average latency from line: %q", statsLine)
	}
	avgStr := matches[1]
	avg, err := strconv.ParseFloat(avgStr, 64)
	if err!= nil {
		if cmdErr!= nil {
			return 0, fmt.Errorf("ping command failed: %w, failed to convert average latency %q to float: %w (full output: %q)", cmdErr, avgStr, err, outputStr)
		}
		return 0, fmt.Errorf("failed to convert average latency %q to float: %w", avgStr, err)
	}
	// Return average even if some pings failed (partial success) as we have valid RTT data
	return avg, nil
}

