)
func parseUnixPingOutput(output string) (float64, error) {
	lines := strings.Split(output, "\n")
	for _, line := range lines {
		if strings.Contains(line, "min/avg/max") {
			parts := strings.SplitN(line, "=", 2)
			if len(parts) < 2 {
				return 0, errors.New("invalid ping summary line: missing '='")
			}
			statsSection := strings.TrimSpace(parts[1])
			statValues := strings.Split(statsSection, " ")
			if len(statValues) == 0 {
				return 0, errors.New("invalid ping summary line: no statistics found")
			}
			latencyValues := strings.Split(statValues[0], "/")
			if len(latencyValues) < 2 {
				return 0, errors.New("invalid ping statistics format: insufficient values")
			}
			avg, err := strconv.ParseFloat(latencyValues[1], 64)
			if err != nil {
				return 0, fmt.Errorf("failed to parse average latency: %w", err)
			}
			return avg, nil
		}
	}
	return 0, errors.New("no ping summary found (possible 100% packet loss or invalid host)")
}
func parseWindowsPingOutput(output string) (float64, error) {
	lines := strings.Split(output, "\n")
	for _, line := range lines {
		if strings.Contains(line, "Average =") {
			parts := strings.SplitN(line, "Average =", 2)
			if len(parts) < 2 {
				return 0, errors.New("invalid average line format")
			}
			avgPart := strings.TrimSpace(parts[1])
			avgStr := strings.Split(avgPart, "ms")[0]
			avgStr = strings.TrimSpace(avgStr)
			avg, err := strconv.ParseFloat(avgStr, 64)
			if err != nil {
				return 0, fmt.Errorf("failed to parse average latency: %w", err)
			}
			return avg, nil
		}
	}
	return 0, errors.New("no average latency found (possible 100% packet loss or invalid host)")
}
func MeasureLatency(host string, count int) (float64, error) {
	if count < 1 {
		return 0, errors.New("count must be a positive integer")
	}
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}
	var args []string
	switch runtime.GOOS {
	case "linux", "darwin":
		args = []string{"-c", strconv.Itoa(count), host}
	case "windows":
		args = []string{"-n", strconv.Itoa(count), host}
	default:
		return 0, fmt.Errorf("unsupported operating system: %s", runtime.GOOS)
	}
	cmd := exec.Command("ping", args...)
	output, err := cmd.Output()
	outputStr := string(output)
	var avg float64
	var parseErr error
	switch runtime.GOOS {
	case "linux", "darwin":
		avg, parseErr = parseUnixPingOutput(outputStr)
	case "windows":
		avg, parseErr = parseWindowsPingOutput(outputStr)
	default:
		return 0, fmt.Errorf("unsupported operating system: %s", runtime.GOOS)
	}
	if parseErr != nil {
		if err != nil {
			return 0, fmt.Errorf("ping execution failed: %w; %w", err, parseErr)
		}
		return 0, parseErr
	}
	return avg, nil
}
func main() {
	if len(os.Args) != 3 {
		fmt.Println("Usage: pingutil <host> <count>")
		fmt.Println("Measures average latency to the specified host using ping.")
		fmt.Println("Example: pingutil google.com 4")
		os.Exit(1)
	}
	host := os.Args[1]
	countStr := os.Args[2]
	count, err := strconv.Atoi(countStr)
	if err != nil || count < 1 {
		fmt.Println("Error: count must be a positive integer")
		os.Exit(1)
	}
	avgLatency, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error measuring latency: %v\n", err)
		os.Exit(1)
	}
	fmt.Printf("Average latency to %s over %d ping(s): %.2f ms\n", host, count, avgLatency)
}

