package main

import (
	"errors"
	"fmt"
	"os"
	"os/exec"
	"runtime"
	"strconv"
	"strings"
)

// MeasureLatency pings the specified host the given number of times and returns the average latency in milliseconds.
// It uses the system 'ping' command via os/exec and parses the output to extract the average RTT.
// Works on Linux, macOS, BSD, BusyBox, and Windows.
func MeasureLatency(host string, count int) (float64, error) {
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be positive")
	}

	// Build ping command with OS-appropriate count flag
	var cmd *exec.Cmd
	if runtime.GOOS == "windows" {
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	} else {
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}

	// Capture output even if command exits with non-zero code (e.g. partial packet loss)
	output, execErr := cmd.CombinedOutput()
	outputStr := string(output)

	var avg float64
	var parseErr error

	if runtime.GOOS == "windows" {
		// Parse Windows ping output format
		lines := strings.Split(outputStr, "\n")
		var avgLine string
		for _, line := range lines {
			if strings.Contains(line, "Average =") {
				avgLine = line
				break
			}
		}

		if avgLine == "" {
			parseErr = errors.New("could not find average latency line in ping output")
		} else {
			avgParts := strings.SplitN(avgLine, "Average =", 2)
			if len(avgParts) < 2 {
				parseErr = errors.New("failed to split average latency line")
			} else {
				avgSegment := strings.TrimSpace(avgParts[1])
				msParts := strings.SplitN(avgSegment, "ms", 2)
				if len(msParts) == 0 {
					parseErr = errors.New("could not find ms unit in average line")
				} else {
					avgStr := strings.TrimSpace(msParts[0])
					avg, parseErr = strconv.ParseFloat(avgStr, 64)
				}
			}
		}
	} else {
		// Parse Unix-like ping output format (Linux, macOS, BSD, BusyBox)
		lines := strings.Split(outputStr, "\n")
		var statsLine string
		for _, line := range lines {
			if strings.Contains(line, "min/avg/max") {
				statsLine = line
				break
			}
		}

		if statsLine == "" {
			parseErr = errors.New("could not find RTT statistics in ping output")
		} else {
			eqParts := strings.SplitN(statsLine, "=", 2)
			if len(eqParts) < 2 {
				parseErr = errors.New("failed to split RTT statistics line on '='")
			} else {
				valuesSegment := strings.TrimSpace(eqParts[1])
				valueFields := strings.Fields(valuesSegment)
				if len(valueFields) == 0 {
					parseErr = errors.New("no RTT values found in statistics line")
				} else {
					rttValues := strings.Split(valueFields[0], "/")
					if len(rttValues) < 2 {
						parseErr = errors.New("insufficient RTT values in statistics line")
					} else {
						// Average is always the second value in min/avg/max[/mdev/stddev] sequence
						avgStr := strings.TrimSpace(rttValues[1])
						avg, parseErr = strconv.ParseFloat(avgStr, 64)
					}
				}
			}
		}
	}

	// Return valid average even if there was an execution error (e.g. partial packet loss)
	if parseErr == nil {
		return avg, nil
	}

	// Combine errors with full output for debugging
	if execErr!= nil {
		return 0, fmt.Errorf("ping execution failed: %w | parsing failed: %w | output: %q", execErr, parseErr, outputStr)
	}
	return 0, fmt.Errorf("ping parsing failed: %w | output: %q", parseErr, outputStr)
}

func main() {
	if len(os.Args)!= 3 {
		fmt.Fprintf(os.Stderr, "Usage: %s <host> <ping-count>\n", os.Args[0])
		os.Exit(1)
	}

	host := os.Args[1]
	countStr := os.Args[2]
	count, err := strconv.Atoi(countStr)
	if err!= nil || count <= 0 {
		fmt.Fprintln(os.Stderr, "Error: ping count must be a positive integer")
		os.Exit(1)
	}

	avgLatency, err := MeasureLatency(host, count)
	if err!= nil {
		fmt.Fprintf(os.Stderr, "Failed to measure latency: %v\n", err)
		os.Exit(1)
	}

	fmt.Printf("Average latency to %s over %d pings: %.2f ms\n", host, count, avgLatency)
}

