package main

import (
	"errors"
	"fmt"
	"os"
	"os/exec"
	"runtime"
	"strconv"
	"strings"
)

// MeasureLatency pings the specified host a given number of times and returns the average latency in milliseconds.
// It uses the system's native ping command via os/exec, supporting Windows, Linux, and macOS.
func MeasureLatency(host string, count int) (float64, error) {
	// Validate input parameters
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}
	if count < 1 {
		return 0, errors.New("count must be a positive integer")
	}

	// Build ping command arguments based on operating system
	var args []string
	if runtime.GOOS == "windows" {
		args = []string{"-n", strconv.Itoa(count), host}
	} else {
		args = []string{"-c", strconv.Itoa(count), host}
	}

	// Execute the ping command and capture combined stdout/stderr
	cmd := exec.Command("ping", args...)
	output, cmdErr := cmd.CombinedOutput()
	outputStr := string(output)
	lines := strings.Split(outputStr, "\n")

	// Parse output based on OS
	if runtime.GOOS == "windows" {
		// Windows ping output format: "Average = Xms"
		for _, line := range lines {
			line = strings.TrimSpace(line)
			avgPrefixIdx := strings.Index(line, "Average = ")
			if avgPrefixIdx == -1 {
				continue
			}

			avgPart := line[avgPrefixIdx+len("Average = "):]
			msSuffixIdx := strings.Index(avgPart, "ms")
			if msSuffixIdx == -1 {
				continue
			}

			avgStr := strings.TrimSpace(avgPart[:msSuffixIdx])
			avg, err := strconv.ParseFloat(avgStr, 64)
			if err == nil {
				return avg, nil
			}
		}
	} else {
		// Unix-like (Linux/macOS) ping output format: "min/avg/max = X/Y/Z ms"
		for _, line := range lines {
			line = strings.TrimSpace(line)
			if !strings.Contains(line, "min/avg/max") {
				continue
			}

			parts := strings.SplitN(line, " = ", 2)
			if len(parts) < 2 {
				continue
			}

			statFields := strings.Split(parts[1], "/")
			if len(statFields) < 2 {
				continue
			}

			avgStr := strings.TrimSpace(statFields[1])
			avg, err := strconv.ParseFloat(avgStr, 64)
			if err == nil {
				return avg, nil
			}
		}
	}

	// If parsing failed, return appropriate error
	if cmdErr != nil {
		return 0, fmt.Errorf("ping command failed: %w, output: %q", cmdErr, outputStr)
	}
	return 0, fmt.Errorf("failed to extract average latency from ping output: %q", outputStr)
}

func main() {
	// Handle command line arguments for demo usage
	if len(os.Args) != 3 {
		fmt.Printf("Usage: %s <host> <ping-count>\n", os.Args[0])
		os.Exit(1)
	}

	host := os.Args[1]
	countStr := os.Args[2]
	count, err := strconv.Atoi(countStr)
	if err != nil || count < 1 {
		fmt.Println("Error: ping count must be a positive integer")
		os.Exit(1)
	}

	avgLatency, err := MeasureLatency(host, count)
	if err != nil {
		fmt.Printf("Error measuring latency: %v\n", err)
		os.Exit(1)
	}

	fmt.Printf("Average latency to %s over %d pings: %.2f ms\n", host, count, avgLatency)
}

