package main

import (
	"errors"
	"fmt"
	"os/exec"
	"strconv"
	"strings"
)

// MeasureLatency pings the specified host count times and returns the average latency in milliseconds
// Uses the system ping command (works for Linux/macOS; replace "-c" with "-n" for Windows compatibility)
func MeasureLatency(host string, count int) (float64, error) {
	// Validate input parameters
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be a positive integer")
	}

	// Construct ping command arguments
	args := []string{"-c", strconv.Itoa(count), host}
	cmd := exec.Command("ping", args...)

	// Execute command and capture combined stdout/stderr for error context
	output, err := cmd.CombinedOutput()
	if err != nil {
		return 0, fmt.Errorf("ping command failed: %w\ncommand output: %s", err, string(output))
	}

	outputStr := string(output)
	lines := strings.Split(outputStr, "\n")

	// Locate the RTT statistics line
	var rttStatsLine string
	for _, line := range lines {
		if strings.Contains(line, "min/avg/max") {
			rttStatsLine = line
			break
		}
	}

	if rttStatsLine == "" {
		return 0, errors.New("no RTT statistics found (all packets may have been lost)")
	}

	// Parse the RTT line format: "rtt min/avg/max/mdev = 1.23/2.34/3.45/0.12 ms"
	parts := strings.Split(rttStatsLine, " = ")
	if len(parts) < 2 {
		return 0, fmt.Errorf("invalid RTT line format: %s", rttStatsLine)
	}

	// Extract the numeric values segment
	statsSegment := parts[1]
	statsFields := strings.Fields(statsSegment)
	if len(statsFields) < 1 {
		return 0, fmt.Errorf("invalid RTT stats format: %s", statsSegment)
	}

	// Split into individual RTT values [min, avg, max, mdev]
	rttValues := strings.Split(statsFields[0], "/")
	if len(rttValues) < 4 {
		return 0, fmt.Errorf("unexpected RTT value format: %s", statsFields[0])
	}

	// Parse average latency (second value in the split result)
	avgLatency, err := strconv.ParseFloat(rttValues[1], 64)
	if err != nil {
		return 0, fmt.Errorf("failed to parse average latency value: %w", err)
	}

	return avgLatency, nil
}

func main() {
	// Example usage of the MeasureLatency function
	targetHost := "google.com"
	pingCount := 3

	avgLatency, err := MeasureLatency(targetHost, pingCount)
	if err != nil {
		fmt.Printf("Latency measurement failed: %v\n", err)
		return
	}

	fmt.Printf("Average latency to %s over %d pings: %.2f ms\n", targetHost, pingCount, avgLatency)
}

