package main
import (
	"errors"
	"fmt"
	"os/exec"
	"strconv"
	"strings"
)
// MeasureLatency pings the specified host the given number of times and returns the average latency in milliseconds.
// It uses the system 'ping' command via os/exec and parses the output to extract the average RTT.
// The average is calculated over successful pings; partial packet loss will not return an error if at least one ping succeeds.
// Supported on Unix-like systems (Linux, macOS, BSD) with standard ping implementations.
func MeasureLatency(host string, count int) (float64, error) {
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be positive")
	}
	// Execute ping command directly without shell to avoid injection and quoting issues
	cmd := exec.Command("ping", "-c", strconv.Itoa(count), host)
	output, pingErr := cmd.CombinedOutput()
	outputStr := string(output)
	// Look for the line containing RTT statistics (works for Linux, macOS/BSD)
	lines := strings.Split(outputStr, "\n")
	var statsLine string
	for _, line := range lines {
		if strings.Contains(line, "min/avg/max") {
			statsLine = line
			break
		}
	}
	if statsLine == "" {
		if pingErr!= nil {
			return 0, fmt.Errorf("ping failed: %w, no RTT statistics found (output: %s)", pingErr, outputStr)
		}
		return 0, fmt.Errorf("no RTT statistics found in ping output: %s", outputStr)
	}
	// Parse the stats line to extract average latency
	splitEq := strings.Split(statsLine, "=")
	if len(splitEq) < 2 {
		return 0, fmt.Errorf("invalid RTT stats line format: %q", statsLine)
	}
	rttFields := strings.Fields(splitEq[1])
	if len(rttFields) < 2 || rttFields[1]!= "ms" {
		return 0, fmt.Errorf("expected RTT unit to be milliseconds (ms) in line: %q", statsLine)
	}
	rttParts := strings.Split(rttFields[0], "/")
	if len(rttParts) < 4 {
		return 0, fmt.Errorf("invalid RTT values format in line: %q", statsLine)
	}
	avgStr := rttParts[1]
	// Handle locales that use comma as decimal separator
	avgStr = strings.ReplaceAll(avgStr, ",", ".")
	avg, err := strconv.ParseFloat(avgStr, 64)
	if err!= nil {
		return 0, fmt.Errorf("failed to parse average latency %q: %w", avgStr, err)
	}
	// Return average even if ping had non-zero exit code (e.g., partial packet loss)
	return avg, nil
}

