package main
import (
	"errors"
	"fmt"
	"os/exec"
	"regexp"
	"runtime"
	"strconv"
	"strings"
)
// Pre-compiled regex patterns for ping output parsing (compiled once at startup for efficiency)
var (
	// Matches RTT statistics line for Unix-like systems (Linux, macOS, BSD)
	unixPingRegex = regexp.MustCompile(`^\s*(?:rtt|round-trip) min/avg/max/(?:mdev|stddev)\s*=\s*[\d.]+/([\d.]+)/[\d.]+/[\d.]+\s*ms\s*$`)
	// Matches average latency line for Windows systems
	windowsPingRegex = regexp.MustCompile(`Average = ([\d.]+)\s*ms`)
)
// MeasureLatency pings the specified host the given number of times and returns the average latency in milliseconds.
// It uses the system 'ping' command via os/exec and parses the output to extract the average RTT.
// Supports Unix-like systems (Linux, macOS, BSD) and Windows.
func MeasureLatency(host string, count int) (float64, error) {
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be positive")
	}
	// Construct OS-appropriate ping command (avoids shell injection by passing arguments directly)
	var cmd *exec.Cmd
	if runtime.GOOS == "windows" {
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), host)
	} else {
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), host)
	}
	// Capture combined stdout/stderr to handle all output and error messages
	output, err := cmd.CombinedOutput()
	outputStr := string(output)
	lines := strings.Split(outputStr, "\n")
	var avgStr string
	var parseErr error
	if runtime.GOOS == "windows" {
		// Parse Windows ping output format
		var avgLine string
		for _, line := range lines {
			if strings.Contains(line, "Average =") {
				avgLine = line
				break
			}
		}
		if avgLine == "" {
			parseErr = errors.New("could not find average latency line in ping output")
		} else {
			matches := windowsPingRegex.FindStringSubmatch(avgLine)
			if len(matches) < 2 {
				parseErr = errors.New("failed to extract average latency from Windows ping output")
			} else {
				avgStr = matches[1]
			}
		}
	} else {
		// Parse Unix-like (Linux, macOS, BSD) ping output format
		var statsLine string
		for _, line := range lines {
			if strings.Contains(line, "min/avg/max") {
				statsLine = line
				break
			}
		}
		if statsLine == "" {
			parseErr = errors.New("could not find RTT statistics line in ping output")
		} else {
			matches := unixPingRegex.FindStringSubmatch(statsLine)
			if len(matches) < 2 {
				parseErr = errors.New("failed to extract average latency from RTT statistics")
			} else {
				avgStr = matches[1]
			}
		}
	}
	// Combine parsing error with execution error if both exist
	if parseErr!= nil {
		if err!= nil {
			return 0, fmt.Errorf("%w: ping command failed: %v (output: %q)", parseErr, err, outputStr)
		}
		return 0, parseErr
	}
	// Convert average string to float64
	avg, err := strconv.ParseFloat(avgStr, 64)
	if err!= nil {
		return 0, fmt.Errorf("failed to parse average latency value %q: %w", avgStr, err)
	}
	// Return average even if ping exited with non-zero (e.g, partial packet loss)
	// Average is still valid for successfully received responses
	return avg, nil
}
// Example main function for testing the MeasureLatency utility
func main() {
	targetHost := "google.com"
	pingCount := 3
	avgLatency, err := MeasureLatency(targetHost, pingCount)
	if err!= nil {
		fmt.Printf("Latency measurement failed: %v\n", err)
		return
	}
	fmt.Printf("Average latency to %s (%d pings): %.2f ms\n", targetHost, pingCount, avgLatency)
}

