package main

import (
	"errors"
	"fmt"
	"os"
	"os/exec"
	"regexp"
	"runtime"
	"strconv"
)

var (
	unixRttRegex     = regexp.MustCompile(`(?:rtt|round-trip) min/avg/max/(?:mdev|stddev) = (\d+\.\d+)/(\d+\.\d+)/\d+\.\d+/\d+\.\d+ ms`)
	windowsPingRegex = regexp.MustCompile(`Average\s*=\s*(\d+(?:\.\d+)?)\s*ms`)
)

// MeasureLatency pings the specified host count times and returns the average latency in milliseconds.
// It uses the system's ping command via os/exec, supporting Windows, Linux, macOS, and BSD systems.
func MeasureLatency(host string, count int) (float64, error) {
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}
	if count < 1 {
		return 0, errors.New("count must be at least 1")
	}

	var cmd *exec.Cmd
	switch runtime.GOOS {
	case "windows":
		// Windows ping uses -n for count, -w for timeout in milliseconds
		cmd = exec.Command("ping", "-n", strconv.Itoa(count), "-w", "5000", host)
	case "linux", "darwin", "freebsd", "openbsd", "netbsd":
		// Unix-like ping uses -c for count, -W for timeout in seconds
		cmd = exec.Command("ping", "-c", strconv.Itoa(count), "-W", "5", host)
	default:
		return 0, fmt.Errorf("unsupported operating system: %s", runtime.GOOS)
	}

	// Capture combined stdout and stderr for comprehensive error reporting
	output, err := cmd.CombinedOutput()
	if err!= nil {
		return 0, fmt.Errorf("ping execution failed: %w\noutput: %s", err, string(output))
	}

	outputStr := string(output)
	var avgStr string

	switch runtime.GOOS {
	case "windows":
		matches := windowsPingRegex.FindStringSubmatch(outputStr)
		if len(matches) < 2 {
			return 0, fmt.Errorf("failed to parse ping output: no average latency found\noutput: %s", outputStr)
		}
		avgStr = matches[1]
	default:
		matches := unixRttRegex.FindStringSubmatch(outputStr)
		if len(matches) < 3 {
			return 0, fmt.Errorf("failed to parse ping output: no average latency found\noutput: %s", outputStr)
		}
		avgStr = matches[2]
	}

	avg, err := strconv.ParseFloat(avgStr, 64)
	if err!= nil {
		return 0, fmt.Errorf("failed to parse average latency value '%s': %w", avgStr, err)
	}

	return avg, nil
}

func main() {
	if len(os.Args)!= 3 {
		fmt.Printf("Usage: %s <host> <ping-count>\n", os.Args[0])
		os.Exit(1)
	}

	host := os.Args[1]
	countStr := os.Args[2]
	count, err := strconv.Atoi(countStr)
	if err!= nil || count < 1 {
		fmt.Println("Error: ping count must be a positive integer")
		os.Exit(1)
	}

	avgLatency, err := MeasureLatency(host, count)
	if err!= nil {
		fmt.Printf("Error measuring latency: %v\n", err)
		os.Exit(1)
	}

	fmt.Printf("Average latency to %s over %d pings: %.2f ms\n", host, count, avgLatency)
}

