	}

	return avgLatency, nil
}

// parseUnixPingOutput extracts average latency from Linux/macOS/BSD ping output
func parseUnixPingOutput(output string) (float64, error) {
	lines := strings.Split(output, "\n")
	for _, line := range lines {
		trimmedLine := strings.TrimSpace(line)
		// Look for the line containing RTT statistics
		if strings.Contains(trimmedLine, "min/avg/max") {
			// Split line to get the values section
			parts := strings.Split(trimmedLine, " = ")
			if len(parts) < 2 {
				return 0, errors.New("invalid RTT line format")
			}

			// Extract the slash-separated latency values
			valueSegment := strings.Fields(parts[1])[0]
			latencyValues := strings.Split(valueSegment, "/")
			if len(latencyValues) < 2 {
