package main
import (
	"errors"
	"fmt"
	"os/exec"
	"regexp"
	"runtime"
	"strconv"
	"strings"
)
// MeasureLatency pings the specified host the given number of times and returns the average latency in milliseconds.
// It uses the system 'ping' command via os/exec and parses the output to extract the average RTT.
// Supports Linux, macOS, and Windows. Partial packet loss is handled by averaging successful pings.
func MeasureLatency(host string, count int) (float64, error) {
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be positive")
	}
	// Construct ping command with OS-appropriate flags, no shell to avoid injection
	var args []string
	if runtime.GOOS == "windows" {
		args = []string{"-n", strconv.Itoa(count), host}
	} else {
		args = []string{"-c", strconv.Itoa(count), host}
	}
	cmd := exec.Command("ping", args...)
	output, cmdErr := cmd.CombinedOutput()
	outputStr := string(output)
	lines := strings.Split(outputStr, "\n")
	var avgStr string
	var parseErr error
	if runtime.GOOS == "windows" {
		// Parse Windows ping output format
		var avgLine string
		for _, line := range lines {
			if strings.Contains(line, "Average =") {
				avgLine = line
				break
			}
		}
		if avgLine == "" {
			parseErr = errors.New("no average latency line found in output")
		} else {
			// Match "Average = Xms" or "Average = X ms", allowing decimal values
			re := regexp.MustCompile(`Average = (\d+(?:\.\d+)?) *ms`)
			matches := re.FindStringSubmatch(avgLine)
			if len(matches) < 2 {
				parseErr = errors.New("failed to extract average from Windows ping output")
			} else {
				avgStr = matches[1]
			}
		}
	} else {
		// Parse Linux/macOS/BSD ping output format
		var statsLine string
		for _, line := range lines {
			if strings.Contains(line, "min/avg/max") {
				statsLine = line
				break
			}
		}
		if statsLine == "" {
			parseErr = errors.New("no RTT statistics line found in output")
		} else {
			// Match the second value (average) in the min/avg/max/... slash-separated list
			re := regexp.MustCompile(`= \d+(?:\.\d+)?/(\d+(?:\.\d+)?)/`)
			matches := re.FindStringSubmatch(statsLine)
			if len(matches) < 2 {
				parseErr = errors.New("failed to extract average from RTT statistics")
			} else {
				avgStr = matches[1]
			}
		}
	}
	// Handle parsing errors, include command error if present
	if parseErr!= nil {
		if cmdErr!= nil {
			return 0, fmt.Errorf("ping command failed: %w; %w (full output: %q)", cmdErr, parseErr, outputStr)
		}
		return 0, fmt.Errorf("%w (full output: %q)", parseErr, outputStr)
	}
	// Convert average string to float64
	avg, err := strconv.ParseFloat(avgStr, 64)
	if err!= nil {
		return 0, fmt.Errorf("invalid average latency value %q: %w", avgStr, err)
	}
	// Return average even if command exited with non-zero (e.g, partial packet loss)
	return avg, nil
}
// Example main function to demonstrate usage
func main() {
	host := "8.8.8.8"
	count := 4
	avg, err := MeasureLatency(host, count)
	if err!= nil {
		fmt.Printf("Failed to measure latency to %s: %v\n", host, err)
		return
	}
	fmt.Printf("Average latency to %s over %d pings: %.2f ms\n", host, count, avg)
}

