import (
	"errors"
	"fmt"
	"os"
	"os/exec"
	"runtime"
	"strconv"
	"strings"
)

// MeasureLatency pings the specified host for count times and returns the average latency in milliseconds
func MeasureLatency(host string, count int) (float64, error) {
	// Validate input parameters
	if host == "" {
		return 0, errors.New("host cannot be empty")
	}
	if count <= 0 {
		return 0, errors.New("count must be a positive integer")
	}

	// Construct ping command arguments based on operating system
	var pingArgs []string
	if runtime.GOOS == "windows" {
		pingArgs = []string{"-n", strconv.Itoa(count), host}
	} else {
		pingArgs = []string{"-c", strconv.Itoa(count), host}
	}

	// Execute ping command and capture combined stdout/stderr
	cmd := exec.Command("ping", pingArgs...)
	output, cmdErr := cmd.CombinedOutput()
	outputStr := string(output)

	// Try to parse latency statistics from output
	var avgLatency float64
	var parseErr error
	if runtime.GOOS == "windows" {
		avgLatency, parseErr = parseWindowsPingOutput(outputStr)
	} else {
		avgLatency, parseErr = parseUnixAverageOutput(outputStr)
	}

	// Return average if parsing succeeded even if command had minor errors (e.g. partial packet loss)
	if parseErr == nil {
		return avgLatency, nil
	}

	// If parsing failed, return appropriate error with context
	if cmdErr!= nil {
		return 0, fmt.Errorf("ping command failed: %w, output: %s", cmdErr, outputStr)
	}
	return 0, fmt.Errorf("failed to parse ping results: %w, output: %s", parseErr, outputStr)
}

// parseUnixAverageOutput parses ping output for Unix-like systems (Linux/macOS/BSD)
func parseUnixAverageOutput(output string) (float64, error) {
	lines := strings.Split(output, "\n")
	for _, line := range lines {
		trimmed := strings.TrimSpace(line)
		// Look for line containing min/avg/max statistics
		if strings.Contains(trimmed, "min/avg/max") {
			parts := strings.Split(trimmed, " = ")
			if len(parts) < 2 {
				continue
			}
			statFields := strings.Split(parts[1], "/")
			if len(statFields) < 2 {
				continue
			}
			avgStr := strings.TrimSpace(statFields[1])
			avg, err := strconv.ParseFloat(avgStr, 64)
			if err!= nil {
				return 0, fmt.Errorf("invalid average value: %s", avgStr)
			}
			return avg, nil
		}
	}
	return 0, errors.New("no latency statistics found in output")
}

// parseWindowsPingOutput parses ping output for Windows systems
func parseWindowsPingOutput(output string) (float64, error) {
	lines := strings.Split(output, "\n")
	for _, line := range lines {
		trimmed := strings.TrimSpace(line)
		// Look for line containing Average metric
		if strings.Contains(trimmed, "Average = ") {
			parts := strings.Split(trimmed, "Average = ")
			if len(parts) < 2 {
				continue
			}
			avgPart := strings.TrimSpace(parts[1])
			avgStr := strings.TrimSuffix(avgPart, "ms")
			avgStr = strings.TrimSpace(avgStr)
			avg, err := strconv.ParseFloat(avgStr, 64)
			if err!= nil {
				return 0, fmt.Errorf("invalid average value: %s", avgPart)
			}
			return avg, nil
		}
	}
	return 0, errors.New("no latency statistics found in output")
}

func main() {
	// Check command line arguments
	if len(os.Args)!= 3 {
		fmt.Printf("Usage: %s <target-host> <ping-count>\n", os.Args[0])
		os.Exit(1)
	}

	host := os.Args[1]
	countStr := os.Args[2]

	// Parse count parameter
	count, err := strconv.Atoi(countStr)
	if err!= nil {
		fmt.Printf("Error: ping count must be a valid integer, got %q\n", countStr)
		os.Exit(1)
	}

	// Measure latency
	avg, err := MeasureLatency(host, count)
	if err!= nil {
		fmt.Printf("Error measuring latency: %v\n", err)
		os.Exit(1)
	}

	// Print result
	fmt.Printf("Average latency to %s over %d pings: %.2f ms\n", host, count, avg)
}

