						break
					}
				}
			}
		}
	default:
		// Parse Unix-like ping output format (looks for min/avg/max metrics)
		for _, line := range lines {
			if strings.Contains(line, "min/avg/max") {
				parts := strings.Split(line, "=")
				if len(parts) >= 2 {
					statsPart := strings.TrimSpace(parts[1])
					statParts := strings.Split(statsPart, "/")
					if len(statParts) >= 2 {
						avgStr = strings.TrimSpace(statParts[1])
						break
					}
				}
			}
		}
	}
	// Handle parsing failure
	if avgStr == "" {
		if err!= nil {
			return 0, fmt.Errorf("ping command failed: %w, output: %s", err, string(output))
		}
		return 0, fmt.Errorf("failed to extract average latency from ping output: %s", string(output))
